from anthropic import Anthropic
from pydantic import BaseModel, Field
from typing import Literal
import boto3, os

# --- Tool input schema (Pydantic for validation) ---
class SendEmailInput(BaseModel):
    to_address: str = Field(
        ...,
        description="Recipient email address",
        # Bounded length; domain restricted to company.com for internal agents
        max_length=254,
        pattern=r'^[a-zA-Z0-9._%+-]+@company\.com$',  # allow-listed domain
    )
    subject: str = Field(..., max_length=200)
    body: str = Field(..., max_length=10_000)

# Reversibility classification: IRREVERSIBLE (email is sent to customer)
# Review decision: Requires human approval gate for emails not matching internal domain
# Permission scope: SES SendEmail permission restricted to verified sender identity only

def send_email_tool(input_data: dict) -> dict:
    """
    Send an email. IRREVERSIBLE — email is delivered immediately.
    Human approval is required for external recipients (enforced at orchestration level).
    Permission: ses:SendEmail on specific verified sender ARN only.
    """
    # Validate input against schema before any AWS call
    try:
        validated = SendEmailInput(**input_data)
    except Exception as e:
        # Return structured error — never raise unhandled exceptions from tool
        return {"success": False, "error": f"Input validation failed: {e}"}

    ses_client = boto3.client(
        'ses',
        region_name=os.environ['SES_REGION'],
        # Credentials from IAM role — never hardcoded
    )

    try:
        response = ses_client.send_email(
            Source=os.environ['SES_SENDER_ADDRESS'],  # Config, not hardcoded
            Destination={'ToAddresses': [validated.to_address]},
            Message={
                'Subject': {'Data': validated.subject},
                'Body': {'Text': {'Data': validated.body}},
            },
        )
        return {
            "success": True,
            "message_id": response['MessageId'],
            "reversible": False,  # Explicit — surfaced to orchestrator for audit
        }
    except ses_client.exceptions.MessageRejected as e:
        return {"success": False, "error": f"SES rejected message: {e}"}
    except Exception as e:
        return {"success": False, "error": f"Send failed: {e}"}
